async function main() {
  console.log('[seed-varieties] Starting variety seed...\n')
  console.log(`[seed-varieties] Total varieties to process: ${VARIETIES.length}\n`)

  let created = 0
  let updated = 0
  let skipped = 0
  let errors = 0

  for (let i = 0; i < VARIETIES.length; i++) {
    const v = VARIETIES[i]
    try {
      // Check if record with this (scientificName, variety) already exists
      const existing = await prisma.plantEntry.findFirst({
        where: {
          scientificName: v.scientificName,
          variety: v.variety,
        },
      })

      const data = {
        commonName: v.commonName,
        scientificName: v.scientificName,
        variety: v.variety,
        category: v.category,
        family: v.family,
        description: v.description ?? null,
        chillHours: v.chillHours ?? null,
        harvestWindow: v.harvestWindow ?? null,
        pollination: v.pollination ?? null,
        sunlight: v.sunlight ?? null,
        waterNeeds: v.waterNeeds ?? null,
        zoneMin: v.zoneMin ?? null,
        zoneMax: v.zoneMax ?? null,
        matureHeight: v.matureHeight ?? null,
        growthHabit: v.growthHabit ?? null,
        perennialYears: v.perennialYears ?? null,
        companionPlants: v.companionPlants ?? null,
        incompatiblePlants: v.incompatiblePlants ?? null,
        commonPests: v.commonPests ?? null,
        careNotes: v.careNotes ?? null,
      }

      if (existing) {
        await prisma.plantEntry.update({
          where: { id: existing.id },
          data,
        })
        updated++
        if ((i + 1) % 20 === 0) process.stdout.write(`  — Updated: ${v.commonName}\n`)
      } else {
        await prisma.plantEntry.create({ data })
        created++
        if ((i + 1) % 20 === 0) process.stdout.write(`  ✓ Created: ${v.commonName}\n`)
      }
    } catch (err: any) {
      errors++
      console.error(`  ✗ Error [${v.commonName}]: ${err.message}`)
    }

    if ((i + 1) % 20 === 0) {
      process.stdout.write(`  Progress: ${i + 1}/${VARIETIES.length} | created: ${created} | updated: ${updated} | skipped: ${skipped} | errors: ${errors}\n`)
    }
  }

  console.log(`\n[seed-varieties] Done! Created: ${created} | Updated: ${updated} | Errors: ${errors}`)

  // Report total with variety set
  const count = await prisma.plantEntry.count({
    where: { variety: { not: null, equals: '' }, },
  })
  console.log(`[seed-varieties] Total records with variety set: ${count}`)

  await prisma.$disconnect()
}

main().catch(async (err) => {
  console.error('[seed-varieties] Fatal:', err)
  await prisma.$disconnect()
  process.exit(1)
})
